const $=(q,ctx=document)=>ctx.querySelector(q);const $$=(q,ctx=document)=>[...ctx.querySelectorAll(q)];
function canvasField(){const c=$('#field');if(!c)return;const x=c.getContext('2d');let w,h,dpr,pts=[];function reset(){dpr=Math.min(devicePixelRatio||1,2);w=c.width=innerWidth*dpr;h=c.height=innerHeight*dpr;c.style.width=innerWidth+'px';c.style.height=innerHeight+'px';pts=Array.from({length:Math.min(120,Math.floor(innerWidth/12))},()=>({x:Math.random()*w,y:Math.random()*h,r:(Math.random()*2+0.6)*dpr,v:(Math.random()*0.22+0.06)*dpr,a:Math.random()*6.28}))}function tick(){x.clearRect(0,0,w,h);for(const p of pts){p.y-=p.v;p.x+=Math.sin(p.a+=.006)*.12*dpr;if(p.y<-10){p.y=h+10;p.x=Math.random()*w}const g=x.createRadialGradient(p.x,p.y,0,p.x,p.y,p.r*6);g.addColorStop(0,'rgba(79,243,255,.55)');g.addColorStop(1,'rgba(255,255,255,0)');x.fillStyle=g;x.beginPath();x.arc(p.x,p.y,p.r*6,0,7);x.fill()}requestAnimationFrame(tick)}reset();addEventListener('resize',reset,{passive:true});tick()}
function counters(){const io=new IntersectionObserver(es=>{for(const e of es){if(!e.isIntersecting)continue;const el=e.target;const target=Number(el.dataset.count||el.textContent.replace(/\D/g,''));let n=0;const step=Math.max(1,Math.ceil(target/38));const t=setInterval(()=>{n+=step;if(n>=target){n=target;clearInterval(t)}el.textContent=target===100?n+'%':n},22);io.unobserve(el)}},{threshold:.4});$$('[data-count]').forEach(el=>io.observe(el))}
function tilt(){for(const card of $$('.stage,.tile')){card.addEventListener('pointermove',e=>{const r=card.getBoundingClientRect(),x=(e.clientX-r.left)/r.width-.5,y=(e.clientY-r.top)/r.height-.5;card.style.transform=`perspective(900px) rotateX(${-y*3}deg) rotateY(${x*3}deg)`});card.addEventListener('pointerleave',()=>card.style.transform='')}}
function intent(){const f=$('#intentForm');if(!f)return;const out=$('#intentOut');f.addEventListener('submit',e=>{e.preventDefault();const data={schema:'goalos.agijobmanager.intent.v2',chainId:1,contract:'0xB3AAeb69b630f0299791679c063d68d6687481d1',token:'0xa61a3b3a130a9c20768eebf97e21515a6046a1fa',action:$('#action').value,role:$('#role').value,mission:$('#mission').value.trim(),evidenceBoundary:'public-safe hashes and manifests only',claimBoundary:'Unsigned planning artifact. No wallet connection, no token approval, no network switch, no transaction broadcast, no fund authorization.',createdAt:new Date().toISOString()};out.textContent=JSON.stringify(data,null,2);$('#downloadIntent').href='data:application/json;charset=utf-8,'+encodeURIComponent(JSON.stringify(data,null,2));$('#downloadIntent').download='goalos-agijobmanager-unsigned-intent.json'});$('#copyIntent')?.addEventListener('click',async()=>{await navigator.clipboard.writeText(out.textContent||'Generate an intent first.');$('#copyIntent').textContent='Copied'})}
function docket(){const btn=$('#downloadDocket');if(!btn)return;const payload={schema:'goalos.evidence_docket.6_1.public',subject:'AGIJobManager Ascension',canonical:{repository:'MontrealAI/goalos-agijobmanager-ascension',url:'https://montrealai.github.io/goalos-agijobmanager-ascension/',contract:'0xB3AAeb69b630f0299791679c063d68d6687481d1',token:'0xa61a3b3a130a9c20768eebf97e21515a6046a1fa'},claims:['public evidence room','read-only operator console','verification manifest','claim boundaries'],nonClaims:['external audit completion','production fund authorization','wallet execution','Mainnet transaction broadcast'],safety:{walletAutoConnect:false,tokenApproval:false,transactionBroadcast:false,privateKeys:false}};btn.href='data:application/json;charset=utf-8,'+encodeURIComponent(JSON.stringify(payload,null,2));btn.download='goalos-agijobmanager-evidence-docket-6-1.json'}
function tabs(){for(const tab of $$('[data-tab]'))tab.addEventListener('click',()=>{const name=tab.dataset.tab;$$('[data-tab]').forEach(t=>t.classList.toggle('active',t===tab));$$('[data-panel]').forEach(p=>p.hidden=p.dataset.panel!==name)})}
document.addEventListener('DOMContentLoaded',()=>{canvasField();counters();tilt();intent();docket();tabs()});
